@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Kanban Board</h2>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger">@_errorMessage</div>
}
else if (_isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">Total</div>
                    <div class="fs-5">@_allTasks.Count</div>
                </div>
            </div>
        </div>
        @foreach (var col in Columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@col</div>
                        <div class="fs-5">@GetTasksForColumn(col).Count</div>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">Overdue</div>
                    <div class="fs-5 text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</div>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (var i = 0; i < Columns.Length; i++)
        {
            var colIndex = i;
            var column = Columns[colIndex];
            var tasks = GetFilteredTasksForColumn(column);

            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body" style="min-height: 200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card mb-2">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="card-text mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_isMoving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex - 1])">
                                                &larr; Move Left
                                            </button>
                                        }
                                        @if (colIndex < Columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_isMoving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex + 1])">
                                                Move Right &rarr;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        <!-- Add Task Form / Button -->
                        @if (_addingToColumn == column)
                        {
                            <div class="card border-primary mt-2">
                                <div class="card-body p-2">
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm"
                                               placeholder="Title" @bind="_newTitle" />
                                    </div>
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm"
                                               placeholder="Assignee" @bind="_newAssignee" />
                                    </div>
                                    <div class="mb-2">
                                        <select class="form-select form-select-sm" @bind="_newPriority">
                                            <option value="High">High</option>
                                            <option value="Medium">Medium</option>
                                            <option value="Low">Low</option>
                                        </select>
                                    </div>
                                    <div class="mb-2">
                                        <input type="date" class="form-control form-control-sm"
                                               @bind="_newDueDate" />
                                    </div>
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm" disabled="@_isSaving"
                                                @onclick="() => SaveNewTaskAsync(column)">
                                            @if (_isSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                            Save
                                        </button>
                                        <button class="btn btn-secondary btn-sm" disabled="@_isSaving"
                                                @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm w-100 mt-2"
                                    @onclick="() => StartAdd(column)">
                                + Add Task
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _isLoading = true;
    private bool _isMoving;
    private bool _isSaving;
    private string? _errorMessage;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchText) ||
                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        _isMoving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            _isMoving = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        _isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // If the service doesn't set the status to the target column, adjust it
            if (created.Status != column)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
                created = created with { Status = column };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            _isSaving = false;
        }
    }
}

